class Category(graphene.ObjectType):
    id = graphene.ID()
    name = graphene.String()
    description = graphene.String()
    products = graphene.List(lambda: Product)

    def resolve_products(self, info):
        return [Product(**p) for p in products_data if p['category_id'] == self.id]


class Review(graphene.ObjectType):
    id = graphene.ID()
    product_id = graphene.ID()
    user_name = graphene.String()
    rating = graphene.Int()
    comment = graphene.String()
    created_at = graphene.String()
    product = graphene.Field(lambda: Product)

    def resolve_product(self, info):
        product = next((p for p in products_data if p['id'] == self.product_id), None)
        return Product(**product) if product else None


class Product(graphene.ObjectType):
    id = graphene.ID()
    name = graphene.String()
    description = graphene.String()
    price = graphene.Float()
    category_id = graphene.ID()
    stock = graphene.Int()
    created_at = graphene.String()
    category = graphene.Field(Category)
    reviews = graphene.List(Review)
    average_rating = graphene.Float()

    def resolve_category(self, info):
        category = next((c for c in categories_data if c['id'] == self.category_id), None)
        return Category(**category) if category else None

    def resolve_reviews(self, info):
        return [Review(**r) for r in reviews_data if r['product_id'] == self.id]

    def resolve_average_rating(self, info):
        product_reviews = [r for r in reviews_data if r['product_id'] == self.id]
        if not product_reviews:
            return 0.0
        total_rating = sum(r['rating'] for r in product_reviews)
        return round(total_rating / len(product_reviews), 2)


class Query(graphene.ObjectType):
    products = graphene.List(
        Product,
        category_id=graphene.ID(),
        min_price=graphene.Float(),
        max_price=graphene.Float(),
        search=graphene.String()
    )
    product = graphene.Field(Product, id=graphene.ID(required=True))
    
    categories = graphene.List(Category)
    category = graphene.Field(Category, id=graphene.ID(required=True))
    
    reviews = graphene.List(
        Review,
        product_id=graphene.ID(),
        min_rating=graphene.Int()
    )
    review = graphene.Field(Review, id=graphene.ID(required=True))

    def resolve_products(self, info, category_id=None, min_price=None, max_price=None, search=None):
        filtered_products = products_data.copy()
        
        if category_id:
            filtered_products = [p for p in filtered_products if p['category_id'] == category_id]
        
        if min_price is not None:
            filtered_products = [p for p in filtered_products if p['price'] >= min_price]
        
        if max_price is not None:
            filtered_products = [p for p in filtered_products if p['price'] <= max_price]
        
        if search:
            search_lower = search.lower()
            filtered_products = [
                p for p in filtered_products 
                if search_lower in p['name'].lower() or search_lower in p['description'].lower()
            ]
        
        return [Product(**p) for p in filtered_products]

    def resolve_product(self, info, id):
        product = next((p for p in products_data if p['id'] == id), None)
        return Product(**product) if product else None

    def resolve_categories(self, info):
        return [Category(**c) for c in categories_data]

    def resolve_category(self, info, id):
        category = next((c for c in categories_data if c['id'] == id), None)
        return Category(**category) if category else None

    def resolve_reviews(self, info, product_id=None, min_rating=None):
        filtered_reviews = reviews_data.copy()
        
        if product_id:
            filtered_reviews = [r for r in filtered_reviews if r['product_id'] == product_id]
        
        if min_rating is not None:
            filtered_reviews = [r for r in filtered_reviews if r['rating'] >= min_rating]
        
        return [Review(**r) for r in filtered_reviews]

    def resolve_review(self, info, id):
        review = next((r for r in reviews_data if r['id'] == id), None)
        return Review(**review) if review else None


schema = graphene.Schema(query=Query)

app.add_url_rule(
    '/graphql',
    view_func=GraphQLView.as_view(
        'graphql',
        schema=schema,
        graphiql=True
    )
)

